import{_ as t,o as n,c as o,a3 as i}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"12. Implementation Committees","description":"","frontmatter":{"title":"12. Implementation Committees","eba":"Mental Health Services 2024-2028","topics":["preliminary"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/preliminary/12-implementation-committees.md","filePath":"ebas/mental-health/common-terms/preliminary/12-implementation-committees.md"}'),s={name:"ebas/mental-health/common-terms/preliminary/12-implementation-committees.md"};function r(a,e,m,l,p,h){return n(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="_12-implementation-committees" tabindex="-1">12. Implementation Committees <a class="header-anchor" href="#_12-implementation-committees" aria-label="Permalink to &quot;12. Implementation Committees&quot;">​</a></h1><p><strong>12.1</strong> The Parties agree to establish a Mental Health Industry Implementation Committee (MHIIC). This Committee will monitor and oversee the implementation of this Agreement. The MHIIC will be chaired by a representative of the Department, and be comprised of representatives of the VHIA (in its capacity as the representative of the Employers), the ANMF and HACSU.</p><p><strong>12.2</strong> The MHIIC will operate in accordance with terms of reference determined by its members.</p><p><strong>12.3</strong> Each Employer shall establish a Mental Health Workplace Implementation Committee (WIC) which may include local and state Union representatives. The WIC shall address local matters directed to the implementation of this Agreement.</p><p><strong>12.4</strong> The WIC will operate in accordance with terms of reference determined by the MHIIC</p><p><strong>12.5</strong> Workplace Implementation Committees</p><p><strong>(a)</strong> A WICs will continue or, if there is not currently a WIC in operation, be established at each Employer. for the purposes of:</p><p><strong>(i)</strong> agreement implementation</p><p><strong>(ii)</strong> on-going monitoring and assessment of the implementation of this Agreement; and</p><p><strong>(iii)</strong> dealing with any local disputes that may arise, without limiting the Dispute Resolution Procedure in this Agreement.</p><p><strong>(b)</strong> Having regard to their size and location, a WIC may be appropriate at each facility/Campus.</p><p><strong>(c)</strong> The WIC will, where practicable, comprise equal numbers of representatives of the Employer and the Unions.</p><p><strong>(d)</strong> The WIC will meet as required to satisfy the purpose described at (a) above and, where a scheduled meeting is cancelled by either party, the responsible party will propose an alternative time within 4 weeks of the previous scheduled meeting.</p><p><strong>(e)</strong> Representatives of the Unions may include nominees of the Unions employed by the Employer, in which case the Employer will provide those nominees paid release from duty to participate.</p><p><strong>(f)</strong> The Employer will make available to the WIC information reasonably necessary to fulfil the objectives at (a) above.</p><p><strong>(g)</strong> Priority items for consideration:</p><p><strong>(i)</strong> Carparking with respect to the safety of Employees, including getting to and from carparking</p><p><strong>(ii)</strong> Operation of the supplementary roster (see <a href="/eba/ebas/mental-health/rpn-pen-mho/hours-of-work/95-supplementary-roster.html">clause 95</a>)</p><p><strong>(iii)</strong> Public holiday rostering requirements</p><p><strong>(iv)</strong> Allocation of paid time for Employees with portfolio or administrative responsibilities (see <a href="/eba/ebas/mental-health/rpn-pen-mho/hours-of-work/96A-portfolio-work-in-paid-time.html">clauses 96A</a> and 125A)</p><p><strong>(v)</strong> Community Mental Health Nursing Positions Data (see <a href="/eba/ebas/mental-health/common-terms/staffing/57-community-mental-health-discipline-mix.html">clause 57.3</a>)</p><p><strong>(vi)</strong> Night shift arrangements</p><p><strong>(vii)</strong> Recruitment to improve Parent Infant Unit staffing profiles (where applicable); and</p><p><strong>(viii)</strong> Implement LLEW classification structure.</p><p><strong>(h)</strong> Other activities undertaken by the WIC include:</p><p><strong>(i)</strong> Gender equity activities, including Audit and Action Plan (standing item);</p><p><strong>(ii)</strong> Engagement with respect to climate change and sustainability activities (where there is not an alternative local mechanism);</p><p><strong>(iii)</strong> Review DWG lists provided in accordance with subclause 69E.1</p><p><strong>(iv)</strong> Working cooperatively to address instances of contact inconsistent with the &#39;Right to Disconnect&#39; clause (see <a href="/eba/ebas/mental-health/common-terms/allowances/36-right-to-disconnect.html">clauses 36</a> and 96B.3)</p><p><strong>(v)</strong> Discuss the Employer&#39;s activities to promote secure employment (see subclause 25.4);</p><p><strong>(vi)</strong> Receiving reports on the following: <strong>(A)</strong> Unresolved Employee requests to rectify underpayments <strong>(B)</strong> The progress of transition to permanent night shift arrangements <strong>(C)</strong> Evaluation of permanent night shift to ensure no unintended consequences <strong>(D)</strong> Evaluation of other night shift arrangements to ensure no unintended consequences <strong>(E)</strong> The positions that are not rostered: <strong>(F)</strong> The results of a review of arrangements for contacting Employee&#39;s out of hours to determine availability; and <strong>(G)</strong> Manual handling where those reports are not provided to an OHS Committee.</p>',31)])])}const d=t(s,[["render",r]]);export{g as __pageData,d as default};
